// Kill-switch service worker.
// Previous versions of this file (generated by next-pwa) aggressively cached
// /_next/static/*, /css/*, and images with CacheFirst, which caused existing
// users to see stale layouts after deploys. This replacement clears all caches
// left behind, unregisters itself, and reloads open tabs so the next request
// goes straight to the network. After this runs once, the browser has no
// service worker at `/` scope and relies on standard HTTP caching.

self.addEventListener('install', () => {
  self.skipWaiting();
});

self.addEventListener('activate', (event) => {
  event.waitUntil((async () => {
    const cacheNames = await caches.keys();
    await Promise.all(cacheNames.map((name) => caches.delete(name)));
    await self.registration.unregister();
    const windowClients = await self.clients.matchAll({ type: 'window' });
    windowClients.forEach((client) => {
      try { client.navigate(client.url); } catch (e) { /* ignore */ }
    });
  })());
});
